module top_module(input [15:0] a, input [1:0] signextsignal, output [31:0] y);reg [31:0] obf_r;
	always@(*)
		case(signextsignal)
			2'b00: obf_r = {{16{a[15]}},a};
			2'b10: obf_r = {16'b0, a};
			2'b11: obf_r = {16'b1111111111111111, a};
			default : obf_r = {{16{a[15]}},a};
		endcase

	assign y = obf_r;

endmodule
